fn recordRpcCall(
  server: VectorGrpcServer,
  latencyMs: f64,
  success: bool
) -> VectorGrpcServer
  let oldAvg = server.stats["avgLatencyMs"] as f64
  let alpha = 0.3
  server.stats["avgLatencyMs"] = (alpha * latencyMs) + ((1.0 - alpha) * oldAvg)

  if !success
    server.stats["failedCalls"] = (server.stats["failedCalls"] as number) + 1

  server

