// ============================================================================
// Phase 4 Module 1: Protocol Buffers - Vector Domain Messages
// 6개 메시지 스키마 + 직렬화/역직렬화
// 400 lines - Wire Format & Binary Serialization
// ============================================================================

struct ProtoField
  fieldNumber: number
  name: string
  fieldType: string
  isRepeated: bool
  wireType: number

struct ProtoSchema
  messageName: string
  fields: array<ProtoField>
  fieldMap: map<string, ProtoField>

struct VectorInsertRequest
  vectorId: string
  dimensions: number
  values: array<f64>

struct VectorInsertResponse
  success: bool
  quorumAchieved: bool
  nodeCount: number

struct VectorSearchRequest
  queryVector: array<f64>
  topK: number
