struct VectorSearchResponse
  results: array<ScoredVector>
  totalSearchMs: number
  partitionCount: number

struct ClusterStatusResponse
  activeNodes: number
  deadNodes: number
  overallHealth: string
  topologyVersion: number

// ============================================================================
// Wire Type Encoding
// ============================================================================

fn wireType_Varint() -> number
  0

fn wireType_I64() -> number
  1

fn wireType_LengthDelimited() -> number
  2

fn wireType_StartGroup() -> number
  3

fn wireType_EndGroup() -> number
  4

fn wireType_I32() -> number
  5

// ============================================================================
// Varint Encoding (Base 128)
// ============================================================================

fn encodeVarint(value: number) -> array<number>
  if value == 0
    return [0]

  var bytes = []
  var v = value

  while v > 0
    var byte = v % 128
    v = v / 128

    if v > 0
      byte = byte | 128  // Set MSB if more bytes follow

    bytes.append(byte)

  bytes

fn decodeVarint(bytes: array<number>, offset: number) -> Result<map<string, any>, string>
  if bytes.length() == 0
    return Err("Empty bytes")

  var value = 0
  var shift = 0
  var pos = offset

  while pos < bytes.length()
    let byte = bytes[pos]
    value = value + ((byte & 0x7F) * (1 << shift))

    if (byte & 0x80) == 0
      return Ok({"value": value, "nextOffset": pos + 1})

    shift = shift + 7
    pos = pos + 1

  Err("Incomplete varint")

// ============================================================================
// Field Tag Encoding: (fieldNumber << 3) | wireType
// ============================================================================

fn encodeFieldTag(fieldNumber: number, wireType: number) -> number
  (fieldNumber << 3) | wireType

fn decodeFieldTag(tag: number) -> map<string, number>
  {
    "fieldNumber": tag >> 3,
    "wireType": tag & 0x07
  }

