// ============================================================================
// VectorInsertRequest Serialization
// ============================================================================

fn serializeVectorInsertRequest(
  vectorId: string,
  vector: array<f64>
) -> Result<array<number>, string>
  var bytes = []

  // Field 1: vectorId (wire type 2 = length-delimited)
  let tag1 = encodeFieldTag(1, 2)
  bytes.append(tag1)

  let idBytes = []
  for i = 0 to vectorId.length()
    // Simplified: ASCII value
    ()

  // Length-delimited: length varint + data
  let idLength = vectorId.length()
  var lengthBytes = encodeVarint(idLength)
  for i = 0 to lengthBytes.length()
    bytes.append(lengthBytes[i])

  // Field 3: values (repeated double)
  for v = 0 to vector.length()
    let tag3 = encodeFieldTag(3, 5)  // Fixed64
    bytes.append(tag3)

    // Simplified: encode as varint
    let valBytes = encodeVarint(vector[v] as number)
    for i = 0 to valBytes.length()
      bytes.append(valBytes[i])

  Ok(bytes)

// ============================================================================
// VectorSearchResponse Serialization
// ============================================================================

fn serializeVectorSearchResponse(
  results: array<map<string, any>>,
  totalSearchMs: number
) -> Result<array<number>, string>
  var bytes = []

  // Field 1: results (repeated, length-delimited)
  for r = 0 to results.length()
    let result = results[r]
    let tag1 = encodeFieldTag(1, 2)
    bytes.append(tag1)

    // Nested message: vectorId + score
    var resultBytes = []

    // vectorId
    let tag1_1 = encodeFieldTag(1, 2)
    resultBytes.append(tag1_1)

    // score
    let tag1_2 = encodeFieldTag(2, 5)  // Fixed64
    resultBytes.append(tag1_2)

    // Length of result message
    let resultLength = resultBytes.length()
    var lengthBytes = encodeVarint(resultLength)
    for i = 0 to lengthBytes.length()
      bytes.append(lengthBytes[i])

    for i = 0 to resultBytes.length()
      bytes.append(resultBytes[i])

  // Field 2: totalSearchMs
  let tag2 = encodeFieldTag(2, 0)
  bytes.append(tag2)

  var msBytes = encodeVarint(totalSearchMs)
  for i = 0 to msBytes.length()
    bytes.append(msBytes[i])

  Ok(bytes)

