  report = report + "Search Streamed: " + (server.stats["searchStreamed"] as number) as string + "\n"
  report = report + "Broadcasts Sent: " + (server.stats["broadcastsSent"] as number) as string + "\n"
  report

fn recordStreamEvent(
  server: VectorStreamServer,
  eventType: string
) -> VectorStreamServer
  match eventType
    "INSERT" -> server.stats["insertStreamed"] = (server.stats["insertStreamed"] as number) + 1
    "SEARCH" -> server.stats["searchStreamed"] = (server.stats["searchStreamed"] as number) + 1
    "BROADCAST" -> server.stats["broadcastsSent"] = (server.stats["broadcastsSent"] as number) + 1
    _ -> ()
  server

